"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[24116],{46314:e=>{e.exports=JSON.parse('{"functions":[{"name":"RegisterTeleportDataProvider","desc":"Registers a provider that contributes teleport data on every [TeleportDataService.BuildTeleportData]\\ncall. Returns a function that unregisters the provider (also give it to a [Maid]).","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"provider","desc":"","lua_type":"TeleportDataProvider"}],"returns":[{"desc":"","lua_type":"() -> ()"}],"function_type":"static","source":{"line":78,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"RegisterPerPlayerTeleportDataProvider","desc":"Registers a per-player provider that contributes each player\'s own slice on every\\n[TeleportDataService.BuildTeleportData] call. Returns a function that unregisters it (also give it\\nto a [Maid]).","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"provider","desc":"","lua_type":"PerPlayerTeleportDataProvider"}],"returns":[{"desc":"","lua_type":"() -> ()"}],"function_type":"static","source":{"line":102,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"BuildTeleportData","desc":"Builds the teleport data for a teleport of the given players as a per-player envelope (see\\n[TeleportDataEnvelopeUtils]): shared-provider contributions plus `baseData` form the shared slice,\\nand each per-player provider\'s contribution forms that player\'s slice. On arrival each player reads\\ntheir own slice merged over the shared one via [TeleportDataService.GetArrivedTeleportData].\\n\\nPrecedence, least to most specific: shared providers, then `baseData` (the caller\'s shared\\noverride), then per-player providers.\\n\\nPure -- performs no teleport -- so it is the seam teleport sites and tests build against. Errors if\\nthe result exceeds the teleport-data size cap, and warns as it approaches it, so an oversized\\npayload fails loudly here instead of being silently dropped by the teleport.","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"players","desc":"","lua_type":"{ Player }"},{"name":"baseData","desc":"shared caller keys, overriding shared providers","lua_type":"{ [string]: any }?"}],"returns":[{"desc":"","lua_type":"{ [string]: any }"}],"function_type":"static","source":{"line":135,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"GetArrivedTeleportData","desc":"Returns the teleport data the player arrived with (from `player:GetJoinData().TeleportData`), or\\nthe value injected by [TeleportDataService.SetArrivedTeleportDataForTesting].","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"player","desc":"","lua_type":"Player"}],"returns":[{"desc":"","lua_type":"{ [string]: any }?"}],"function_type":"static","source":{"line":210,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"_getUserId","desc":"Resolves the UserId used to key a player\'s envelope slice. A method so tests can stand in a fake\\nplayer (which has no UserId) by overriding it.","params":[{"name":"_self","desc":"","lua_type":"TeleportDataService"},{"name":"player","desc":"","lua_type":"Player"}],"returns":[{"desc":"","lua_type":"number"}],"function_type":"static","source":{"line":244,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"GetArrivedValue","desc":"Returns the value the player arrived with under `key`, or nil.","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"player","desc":"","lua_type":"Player"},{"name":"key","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"any"}],"function_type":"static","source":{"line":255,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"HasArrivedValue","desc":"Returns whether the player arrived with a value under `key`.","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"player","desc":"","lua_type":"Player"},{"name":"key","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"static","source":{"line":273,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"SetArrivedTeleportDataForTesting","desc":"Overrides the arrived teleport data for a player. Test seam -- headless servers have no joined\\nplayers, so specs inject the data a player would have arrived with.","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"player","desc":"","lua_type":"Player"},{"name":"data","desc":"","lua_type":"{ [string]: any }?"}],"returns":[],"function_type":"static","source":{"line":284,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}}],"properties":[],"types":[{"name":"TeleportDataProvider","desc":"Contributes teleport data shared by *every* player in a teleport. Returns nil to contribute\\nnothing.","lua_type":"({ Player }) -> ({ [string]: any }?)","source":{"line":29,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"PerPlayerTeleportDataProvider","desc":"Contributes teleport data for a *single* player in a teleport (called once per player, with the\\nfull player list for context). Returns nil to contribute nothing. This is how per-player data\\nsurvives a group teleport, where every player would otherwise share one flat table.","lua_type":"(Player, { Player }) -> ({ [string]: any }?)","source":{"line":39,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}}],"name":"TeleportDataService","desc":"Central place to assemble the [TeleportData] a teleport should carry. Systems register a\\nprovider once (analytics, save-slot id, ...) and every teleport site builds its data through\\n[TeleportDataService.BuildTeleportData] instead of hand-writing the same table -- so a site can\\nnever forget to attach the shared data, and the assembly is unit testable.\\n\\nThis service only *builds* data and *reads* the data a player arrived with; it deliberately does\\nnot wrap the teleport call itself (that stays on [TeleportServiceUtils]), so we are never forced\\nto route every teleport through here.","realm":["Server"],"source":{"line":15,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}}')}}]);